  1→import { useState } from 'react';
  2→import { Link } from 'react-router';
  3→import { useDashboardStats, useUsageStats } from '@/hooks/useAnalytics';
  4→import { useSessions } from '@/hooks/useSessions';
  5→import { useInsights } from '@/hooks/useInsights';
  6→import { useProjects } from '@/hooks/useProjects';
  7→import { StatsHero } from '@/components/dashboard/StatsHero';
  8→import { DashboardActivityChart } from '@/components/dashboard/DashboardActivityChart';
  9→import { ActivityFeed } from '@/components/dashboard/ActivityFeed';
 10→import { BulkAnalyzeButton } from '@/components/analysis/BulkAnalyzeButton';
 11→import { StatsHeroSkeleton } from '@/components/skeletons/StatsHeroSkeleton';
 12→import { ErrorCard } from '@/components/ErrorCard';
 13→import { Card, CardContent, CardHeader } from '@/components/ui/card';
 14→import { Skeleton } from '@/components/ui/skeleton';
 15→import { formatDurationMinutes } from '@/lib/utils';
 16→import { Sparkles, ArrowRight } from 'lucide-react';
 17→
 18→type DashboardRange = '30d' | '90d' | 'all';
 19→
 20→function getGreeting(): string {
 21→  const hour = new Date().getHours();
 22→  if (hour < 12) return 'Good morning';
 23→  if (hour < 17) return 'Good afternoon';
 24→  return 'Good evening';
 25→}
 26→
 27→export default function DashboardPage() {
 28→  const [range, setRange] = useState<DashboardRange>('30d');
 29→
 30→  const { data: dashStats, isLoading: statsLoading, isError: statsError, refetch: refetchStats } = useDashboardStats(range);
 31→  const { data: usageStats } = useUsageStats();
 32→  const { data: sessions = [], isLoading: sessionsLoading, isError: sessionsError, refetch: refetchSessions } = useSessions({ limit: 20 });
 33→  const { data: insights = [], isLoading: insightsLoading } = useInsights();
 34→  const { data: projects = [] } = useProjects();
 35→
 36→  const loading = statsLoading || sessionsLoading || insightsLoading;
 37→  const hasError = statsError || sessionsError;
 38→
 39→  const todayLabel = new Date().toLocaleDateString(undefined, {
 40→    month: 'long',
 41→    day: 'numeric',
 42→  });
 43→
 44→  // Sessions not yet analyzed
 45→  const analyzedSessionIds = new Set(insights.map((i) => i.session_id));
 46→  const unanalyzedSessions = sessions.filter((s) => !analyzedSessionIds.has(s.id));
 47→
 48→  // Compute stats for hero
 49→  const usageStatsData = usageStats as {
 50→    total_input_tokens?: number;
 51→    total_output_tokens?: number;
 52→    cache_creation_tokens?: number;
 53→    cache_read_tokens?: number;
 54→    estimated_cost_usd?: number;
 55→  } | null;
 56→
 57→  const totalTokens = usageStatsData
 58→    ? (usageStatsData.total_input_tokens ?? 0) +
 59→      (usageStatsData.total_output_tokens ?? 0) +
 60→      (usageStatsData.cache_creation_tokens ?? 0) +
 61→      (usageStatsData.cache_read_tokens ?? 0)
 62→    : (dashStats?.total_input_tokens ?? 0) + (dashStats?.total_output_tokens ?? 0);
 63→
 64→  const totalCost =
 65→    usageStatsData?.estimated_cost_usd ?? dashStats?.estimated_cost_usd ?? 0;
 66→
 67→  const tokenBreakdown = usageStatsData
 68→    ? {
 69→        inputTokens: usageStatsData.total_input_tokens ?? 0,
 70→        outputTokens: usageStatsData.total_output_tokens ?? 0,
 71→        cacheCreationTokens: usageStatsData.cache_creation_tokens ?? 0,
 72→        cacheReadTokens: usageStatsData.cache_read_tokens ?? 0,
 73→      }
 74→    : undefined;
 75→
 76→  return (
 77→    <div className="p-4 lg:p-6 space-y-3">
 78→      {/* Greeting header */}
 79→      <div className="flex items-start justify-between">
 80→        <div>
 81→          <h1 className="text-2xl font-bold">{getGreeting()}.</h1>
 82→          {!loading && (
 83→            <p className="text-muted-foreground text-sm mt-1 animate-in fade-in slide-in-from-bottom-2 duration-300">
 84→              {sessions.length} session{sessions.length !== 1 ? 's' : ''} loaded
 85→              {' '}&middot; {projects.length} project{projects.length !== 1 ? 's' : ''}
 86→            </p>
 87→          )}
 88→        </div>
 89→        <span className="text-sm text-muted-foreground">{todayLabel}</span>
 90→      </div>
 91→
 92→      {/* Error state */}
 93→      {hasError && !loading && (
 94→        <ErrorCard
 95→          message="Failed to load dashboard data"
 96→          onRetry={() => { refetchStats(); refetchSessions(); }}
 97→        />
 98→      )}
 99→
100→      {/* All-time stats hero */}
101→      {loading ? (
102→        <StatsHeroSkeleton />
103→      ) : (
104→        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
105→          <StatsHero
106→            totalSessions={dashStats?.session_count ?? sessions.length}
107→            totalMessages={dashStats?.total_messages ?? 0}
108→            totalToolCalls={0}
109→            totalDurationMin={0}
110→            totalProjects={projects.length}
111→            isExact={true}
112→            totalTokens={totalTokens > 0 ? totalTokens : undefined}
113→            totalCost={totalCost > 0 ? totalCost : undefined}
114→            tokenBreakdown={tokenBreakdown}
115→          />
116→        </div>
117→      )}
118→
119→      {/* Activity chart */}
120→      {loading ? (
121→        <Card>
122→          <CardHeader className="flex flex-row items-center justify-between pb-1">
123→            <Skeleton className="h-4 w-16" />
124→            <div className="flex gap-1">
125→              <Skeleton className="h-7 w-10 rounded" />
126→              <Skeleton className="h-7 w-10 rounded" />
127→              <Skeleton className="h-7 w-8 rounded" />
128→            </div>
129→          </CardHeader>
130→          <CardContent>
131→            <Skeleton className="h-[250px] w-full rounded" />
132→          </CardContent>
133→        </Card>
134→      ) : (
135→        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-150">
136→          <DashboardActivityChart data={[]} range={range} onRangeChange={setRange} />
137→        </div>
138→      )}
139→
140→      {/* Needs Attention banner */}
141→      {unanalyzedSessions.length > 0 && (
142→        <Card className="border-amber-500/20 bg-amber-500/5 hover:shadow-md transition-shadow animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
143→          <CardContent className="flex items-center justify-between py-4">
144→            <div className="flex items-center gap-2">
145→              <Sparkles className="h-4 w-4 text-amber-600" />
146→              <div>
147→                <p className="text-sm font-medium">
148→                  {unanalyzedSessions.length} session{unanalyzedSessions.length !== 1 ? 's' : ''}{' '}
149→                  without analysis
150→                </p>
151→                <p className="text-xs text-muted-foreground">
152→                  Generate AI insights to extract learnings and decisions
153→                </p>
154→              </div>
155→            </div>
156→            <BulkAnalyzeButton sessions={unanalyzedSessions} />
157→          </CardContent>
158→        </Card>
159→      )}
160→
161→      {/* Unified activity feed */}
162→      <div
163→        className={
164→          loading ? '' : 'animate-in fade-in slide-in-from-bottom-2 duration-300 delay-300'
165→        }
166→      >
167→        <div className="flex items-center justify-between mb-2">
168→          <h2 className="text-sm font-semibold">Recent Activity</h2>
169→          <Link
170→            to="/sessions"
171→            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
172→          >
173→            View all
174→            <ArrowRight className="h-3 w-3" />
175→          </Link>
176→        </div>
177→        <Card>
178→          <CardContent className="px-4 py-2">
179→            {loading ? (
180→              <div className="divide-y divide-border">
181→                {[...Array(4)].map((_, i) => (
182→                  <div key={i} className="py-2">
183→                    <div className="flex items-center justify-between gap-2">
184→                      <div className="flex items-center gap-2 min-w-0">
185→                        <Skeleton className="h-6 w-6 rounded-md shrink-0" />
186→                        <Skeleton className="h-4 w-48" />
187→                        <Skeleton className="h-3.5 w-20" />
188→                      </div>
189→                      <Skeleton className="h-3.5 w-16 shrink-0" />
190→                    </div>
191→                  </div>
192→                ))}
193→              </div>
194→            ) : (
195→              <ActivityFeed sessions={sessions} insights={insights} limit={7} />
196→            )}
197→          </CardContent>
198→        </Card>
199→      </div>
200→    </div>
201→  );
202→}
