  1→import { useMemo } from 'react';
  2→import {
  3→  AreaChart,
  4→  Area,
  5→  XAxis,
  6→  YAxis,
  7→  CartesianGrid,
  8→  Tooltip,
  9→  ResponsiveContainer,
 10→} from 'recharts';
 11→import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
 12→import { Button } from '@/components/ui/button';
 13→import { useThemeColors } from '@/lib/hooks/useThemeColors';
 14→import { CHART_COLORS } from '@/lib/constants/colors';
 15→import type { DailyStats } from '@/lib/types';
 16→
 17→type DashboardRange = '30d' | '90d' | 'all';
 18→
 19→interface DashboardActivityChartProps {
 20→  data: DailyStats[];
 21→  range: DashboardRange;
 22→  onRangeChange: (range: DashboardRange) => void;
 23→}
 24→
 25→const rangeOptions: { value: DashboardRange; label: string }[] = [
 26→  { value: '30d', label: '30d' },
 27→  { value: '90d', label: '90d' },
 28→  { value: 'all', label: 'All' },
 29→];
 30→
 31→export function DashboardActivityChart({ data, range, onRangeChange }: DashboardActivityChartProps) {
 32→  const { tooltipBg, tooltipBorder } = useThemeColors();
 33→
 34→  const chartData = useMemo(
 35→    () =>
 36→      data.map((d) => ({
 37→        ...d,
 38→        date: new Date(d.date).toLocaleDateString('en-US', {
 39→          month: 'short',
 40→          day: 'numeric',
 41→        }),
 42→        // Normalize field names to match recharts dataKey
 43→        sessionCount: d.session_count,
 44→        insightCount: d.insight_count,
 45→      })),
 46→    [data]
 47→  );
 48→
 49→  return (
 50→    <Card>
 51→      <CardHeader className="flex flex-row items-center justify-between pb-1">
 52→        <CardTitle className="text-sm font-medium">Activity</CardTitle>
 53→        <div className="flex gap-1">
 54→          {rangeOptions.map(({ value, label }) => (
 55→            <Button
 56→              key={value}
 57→              variant={range === value ? 'default' : 'ghost'}
 58→              size="sm"
 59→              className="h-7 px-2.5 text-xs"
 60→              onClick={() => onRangeChange(value)}
 61→            >
 62→              {label}
 63→            </Button>
 64→          ))}
 65→        </div>
 66→      </CardHeader>
 67→      <CardContent>
 68→        <div className="h-[250px]">
 69→          {chartData.length > 0 ? (
 70→            <ResponsiveContainer width="100%" height="100%">
 71→              <AreaChart data={chartData}>
 72→                <defs>
 73→                  <linearGradient id="dashColorSessions" x1="0" y1="0" x2="0" y2="1">
 74→                    <stop offset="5%" stopColor={CHART_COLORS.activity.sessions} stopOpacity={0.3} />
 75→                    <stop offset="95%" stopColor={CHART_COLORS.activity.sessions} stopOpacity={0} />
 76→                  </linearGradient>
 77→                  <linearGradient id="dashColorInsights" x1="0" y1="0" x2="0" y2="1">
 78→                    <stop offset="5%" stopColor={CHART_COLORS.activity.insights} stopOpacity={0.3} />
 79→                    <stop offset="95%" stopColor={CHART_COLORS.activity.insights} stopOpacity={0} />
 80→                  </linearGradient>
 81→                </defs>
 82→                <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
 83→                <XAxis
 84→                  dataKey="date"
 85→                  tick={{ fontSize: 11 }}
 86→                  tickLine={false}
 87→                  axisLine={false}
 88→                  className="text-muted-foreground"
 89→                  interval={range === '30d' ? 4 : range === '90d' ? 13 : 'preserveStartEnd'}
 90→                />
 91→                <YAxis
 92→                  tick={{ fontSize: 11 }}
 93→                  tickLine={false}
 94→                  axisLine={false}
 95→                  className="text-muted-foreground"
 96→                  width={30}
 97→                />
 98→                <Tooltip
 99→                  contentStyle={{
100→                    backgroundColor: tooltipBg,
101→                    borderColor: tooltipBorder,
102→                    borderRadius: '8px',
103→                    fontSize: '12px',
104→                  }}
105→                />
106→                <Area
107→                  type="monotone"
108→                  dataKey="sessionCount"
109→                  name="Sessions"
110→                  stroke={CHART_COLORS.activity.sessions}
111→                  fillOpacity={1}
112→                  fill="url(#dashColorSessions)"
113→                />
114→                <Area
115→                  type="monotone"
116→                  dataKey="insightCount"
117→                  name="Insights"
118→                  stroke={CHART_COLORS.activity.insights}
119→                  fillOpacity={1}
120→                  fill="url(#dashColorInsights)"
121→                />
122→              </AreaChart>
123→            </ResponsiveContainer>
124→          ) : (
125→            <div className="flex h-full items-center justify-center">
126→              <p className="text-sm text-muted-foreground">No activity data yet</p>
127→            </div>
128→          )}
129→        </div>
130→      </CardContent>
131→    </Card>
132→  );
133→}
