 1→import { useQuery } from '@tanstack/react-query';
 2→import { fetchDashboardStats, fetchUsageStats } from '@/lib/api';
 3→
 4→type Range = '7d' | '30d' | '90d' | 'all';
 5→
 6→export function useDashboardStats(range: Range = '7d') {
 7→  return useQuery({
 8→    queryKey: ['analytics', 'dashboard', range],
 9→    queryFn: () => fetchDashboardStats(range).then((r) => r.stats),
10→  });
11→}
12→
13→export function useUsageStats() {
14→  return useQuery({
15→    queryKey: ['analytics', 'usage'],
16→    queryFn: () => fetchUsageStats().then((r) => r.stats),
17→  });
18→}
