  1→// HTTP client for the Hono API server.
  2→// Base URL is relative in production (SPA served by the same server).
  3→// In Vite dev mode, the proxy forwards /api -> localhost:7890.
  4→
  5→import type { Project, Session, Message, Insight, DashboardStats, LLMConfig } from '@/lib/types';
  6→
  7→const BASE = '/api';
  8→
  9→async function request<T>(path: string, init?: RequestInit): Promise<T> {
 10→  // Only set Content-Type when a body is present — setting it on GET requests
 11→  // adds unnecessary headers and can confuse some intermediaries.
 12→  const headers: Record<string, string> = { ...(init?.headers as Record<string, string>) };
 13→  if (init?.body) {
 14→    headers['Content-Type'] = 'application/json';
 15→  }
 16→  const res = await fetch(`${BASE}${path}`, { ...init, headers });
 17→  if (!res.ok) {
 18→    const text = await res.text().catch(() => res.statusText);
 19→    throw new Error(`API ${res.status}: ${text}`);
 20→  }
 21→  return res.json() as Promise<T>;
 22→}
 23→
 24→// ── Projects ──────────────────────────────────────────────────────────────────
 25→
 26→export function fetchProjects() {
 27→  return request<{ projects: Project[] }>('/projects');
 28→}
 29→
 30→export function fetchProject(id: string) {
 31→  return request<{ project: Project }>(`/projects/${id}`);
 32→}
 33→
 34→// ── Sessions ──────────────────────────────────────────────────────────────────
 35→
 36→export function fetchSessions(params?: {
 37→  projectId?: string;
 38→  sourceTool?: string;
 39→  limit?: number;
 40→  offset?: number;
 41→}) {
 42→  const q = new URLSearchParams();
 43→  if (params?.projectId) q.set('projectId', params.projectId);
 44→  if (params?.sourceTool) q.set('sourceTool', params.sourceTool);
 45→  if (params?.limit !== undefined) q.set('limit', String(params.limit));
 46→  if (params?.offset !== undefined) q.set('offset', String(params.offset));
 47→  const qs = q.toString() ? `?${q.toString()}` : '';
 48→  return request<{ sessions: Session[] }>(`/sessions${qs}`);
 49→}
 50→
 51→export function fetchSession(id: string) {
 52→  return request<{ session: Session }>(`/sessions/${id}`);
 53→}
 54→
 55→export function patchSession(id: string, body: { customTitle: string }) {
 56→  return request<{ ok: boolean }>(`/sessions/${id}`, {
 57→    method: 'PATCH',
 58→    body: JSON.stringify(body),
 59→  });
 60→}
 61→
 62→// ── Messages ──────────────────────────────────────────────────────────────────
 63→
 64→export function fetchMessages(sessionId: string, params?: { limit?: number; offset?: number }) {
 65→  const q = new URLSearchParams();
 66→  if (params?.limit !== undefined) q.set('limit', String(params.limit));
 67→  if (params?.offset !== undefined) q.set('offset', String(params.offset));
 68→  const qs = q.toString() ? `?${q.toString()}` : '';
 69→  return request<{ messages: Message[] }>(`/messages/${sessionId}${qs}`);
 70→}
 71→
 72→// ── Insights ──────────────────────────────────────────────────────────────────
 73→
 74→export function fetchInsights(params?: {
 75→  projectId?: string;
 76→  sessionId?: string;
 77→  type?: string;
 78→}) {
 79→  const q = new URLSearchParams();
 80→  if (params?.projectId) q.set('projectId', params.projectId);
 81→  if (params?.sessionId) q.set('sessionId', params.sessionId);
 82→  if (params?.type) q.set('type', params.type);
 83→  const qs = q.toString() ? `?${q.toString()}` : '';
 84→  return request<{ insights: Insight[] }>(`/insights${qs}`);
 85→}
 86→
 87→export function deleteInsight(id: string) {
 88→  return request<{ ok: boolean }>(`/insights/${id}`, { method: 'DELETE' });
 89→}
 90→
 91→// ── Analytics ─────────────────────────────────────────────────────────────────
 92→
 93→export function fetchDashboardStats(range: '7d' | '30d' | '90d' | 'all' = '7d') {
 94→  return request<{ range: string; stats: DashboardStats }>(`/analytics/dashboard?range=${range}`);
 95→}
 96→
 97→export function fetchUsageStats() {
 98→  return request<{ stats: unknown }>('/analytics/usage');
 99→}
100→
101→// ── Analysis (Phase 4) ────────────────────────────────────────────────────────
102→
103→export function analyzeSession(sessionId: string) {
104→  return request<unknown>('/analysis/session', {
105→    method: 'POST',
106→    body: JSON.stringify({ sessionId }),
107→  });
108→}
109→
110→// ── Config ────────────────────────────────────────────────────────────────────
111→
112→export function fetchLlmConfig() {
113→  return request<LLMConfig>('/config/llm');
114→}
115→
116→export function saveLlmConfig(body: {
117→  dashboardPort?: number;
118→  provider?: string;
119→  model?: string;
120→  apiKey?: string;
121→  baseUrl?: string;
122→}) {
123→  return request<{ ok: boolean }>('/config/llm', {
124→    method: 'PUT',
125→    body: JSON.stringify(body),
126→  });
127→}
128→
129→export function testLlmConfig(body?: {
130→  provider?: string;
131→  model?: string;
132→  apiKey?: string;
133→  baseUrl?: string;
134→}) {
135→  return request<{ success: boolean; error?: string }>('/config/llm/test', {
136→    method: 'POST',
137→    body: JSON.stringify(body ?? {}),
138→  });
139→}
140→
141→export function fetchOllamaModels(baseUrl?: string) {
142→  const qs = baseUrl ? `?baseUrl=${encodeURIComponent(baseUrl)}` : '';
143→  return request<{ models: Array<{ name: string; size: number; modifiedAt: string }> }>(
144→    `/config/llm/ollama-models${qs}`
145→  );
146→}
147→
148→export function analyzePromptQuality(sessionId: string) {
149→  return request<unknown>('/analysis/prompt-quality', {
150→    method: 'POST',
151→    body: JSON.stringify({ sessionId }),
152→  });
153→}
154→
155→export function findRecurringInsights(body?: { projectId?: string; limit?: number }) {
156→  return request<unknown>('/analysis/recurring', {
157→    method: 'POST',
158→    body: JSON.stringify(body ?? {}),
159→  });
160→}
161→
162→// ── Export ────────────────────────────────────────────────────────────────────
163→
164→export async function exportMarkdown(body: {
165→  sessionIds?: string[];
166→  projectId?: string;
167→}): Promise<string> {
168→  const res = await fetch(`${BASE}/export/markdown`, {
169→    method: 'POST',
170→    headers: { 'Content-Type': 'application/json' },
171→    body: JSON.stringify(body),
172→  });
173→  if (!res.ok) {
174→    const text = await res.text().catch(() => res.statusText);
175→    throw new Error(`Export failed ${res.status}: ${text}`);
176→  }
177→  return res.text();
178→}
