 1→import { Hono } from 'hono';
 2→import { getDb } from '@code-insights/cli/db/client';
 3→
 4→const app = new Hono();
 5→
 6→const VALID_RANGES = ['7d', '30d', '90d', 'all'] as const;
 7→type Range = typeof VALID_RANGES[number];
 8→
 9→// Dashboard overview stats for a given time range (e.g. ?range=7d|30d|90d|all)
10→app.get('/dashboard', (c) => {
11→  const db = getDb();
12→  const { range = '7d' } = c.req.query();
13→
14→  if (!VALID_RANGES.includes(range as Range)) {
15→    return c.json({ error: `Invalid range. Must be one of: ${VALID_RANGES.join(', ')}` }, 400);
16→  }
17→
18→  let periodStart: string | null = null;
19→  const now = new Date();
20→  if (range === '7d') {
21→    periodStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
22→  } else if (range === '30d') {
23→    periodStart = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();
24→  } else if (range === '90d') {
25→    periodStart = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000).toISOString();
26→  }
27→
28→  const where = periodStart ? 'WHERE started_at >= ?' : '';
29→  const params = periodStart ? [periodStart] : [];
30→
31→  const stats = db.prepare(`
32→    SELECT
33→      COUNT(*) AS session_count,
34→      SUM(message_count) AS total_messages,
35→      SUM(total_input_tokens) AS total_input_tokens,
36→      SUM(total_output_tokens) AS total_output_tokens,
37→      SUM(estimated_cost_usd) AS estimated_cost_usd
38→    FROM sessions ${where}
39→  `).get(...params);
40→
41→  return c.json({ range, stats });
42→});
43→
44→// Global cumulative usage stats
45→app.get('/usage', (c) => {
46→  const db = getDb();
47→  const stats = db.prepare(`
48→    SELECT total_input_tokens, total_output_tokens, cache_creation_tokens,
49→           cache_read_tokens, estimated_cost_usd, sessions_with_usage, last_updated_at
50→    FROM usage_stats WHERE id = 1
51→  `).get();
52→  return c.json({ stats: stats ?? null });
53→});
54→
55→export default app;
